mapper.select:
SELECT id, rule_name, description, category_code, script, status, deleted_flag, crte_time, updt_time FROM rule_definition
IFNULL(deleted_flag, 0) = 0
AND status = #{status}
AND ( rule_name LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%') OR EXISTS ( SELECT 1 FROM rule_param p WHERE p.rule_id = rule_definition.id AND (p.param_name LIKE CONCAT('%', #{keyword}, '%') OR p.param_label LIKE CONCAT('%', #{keyword}, '%')) ) )
ORDER BY crte_time DESC, id DESC LIMIT #{offset}, #{pageSize}

SELECT id, rule_id, param_name, param_label, param_type, required, sort_no, crte_time, updt_time
FROM rule_param WHERE rule_id = #{ruleId}
ORDER BY sort_no ASC, id ASC

mapper.delete:
DELETE FROM rule_param_option WHERE param_id IN (
    SELECT id FROM rule_param WHERE rule_id = #{ruleId}
)
